\displaystyle{\begin{aligned}
  \frac{{\frac{7}{b-1}-5}}{{\frac{1}{b-1}+\frac{1}{b-10}}} \amp = \frac{({\frac{7}{b-1}-5})\cdot{\left(b-1\right)\mathopen{}\left(b-10\right)}}{({\frac{1}{b-1}+\frac{1}{b-10}})\cdot{\left(b-1\right)\mathopen{}\left(b-10\right)}} \\
    \amp = \frac{{\frac{7}{b-1}\mathopen{}\left(b-1\right)\mathopen{}\left(b-10\right)-5\mathopen{}\left(b-1\right)\mathopen{}\left(b-10\right)}}{{\frac{1}{b-1}\mathopen{}\left(b-1\right)\mathopen{}\left(b-10\right)+\frac{1}{b-10}\mathopen{}\left(b-1\right)\mathopen{}\left(b-10\right)}} \\
    \amp = \frac{{7\mathopen{}\left(b-10\right)-5\mathopen{}\left(b^{2}-11b+10\right)}}{{b-10+b-1}}, b \ne 1 \text{ and } b \ne 10 \\
    \amp = \frac{{7b-70-5b^{2}+55b-50}}{{2b-11}}, b \ne 1 \text{ and }  b \ne 10 \\
    \amp = \frac{{-5b^{2}+62b-50}}{{2b-11}}, b \ne 1 \text{ and }  b \ne 10 \\
    \amp = {-\frac{\left(5b-12\right)\mathopen{}\left(b-10\right)}{2b-11}, b\ne 1\hbox{ and }b\ne 10}
\end{aligned}
    }
